class Solution:
    def smallestRangeII(self, nums, k):
        n = len(nums)
        best = max(nums) - min(nums)
        for mask_split in range(n + 1):
            s = sorted(nums)
            adjusted = [s[i] + k if i < mask_split else s[i] - k for i in range(n)]
            best = min(best, max(adjusted) - min(adjusted))
        return best

